<?php session_start(); require 'includes/header.php'; require_login();
if($_SERVER['REQUEST_METHOD']==='POST' && can_manage()){ $st=$pdo->prepare('INSERT INTO items(item_code,barcode,name,category_id,unit,brand,location,rack,shelf,min_stock,current_stock,unit_price) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)'); $st->execute([$_POST['item_code'],$_POST['barcode'],$_POST['name'],$_POST['category_id'],$_POST['unit'],$_POST['brand'],$_POST['location'],$_POST['rack'],$_POST['shelf'],$_POST['min_stock'],$_POST['current_stock'],$_POST['unit_price']]); log_action($pdo,'Item added',$_POST['name']); header('Location:items.php'); exit; }
$cats=$pdo->query('SELECT * FROM categories ORDER BY name')->fetchAll(); $rows=$pdo->query('SELECT items.*,categories.name cat FROM items LEFT JOIN categories ON categories.id=items.category_id ORDER BY items.name')->fetchAll();
?><h1>Items</h1><div class="card"><h3>Add Item</h3><form method="post" class="formgrid"><input name="item_code" placeholder="Item Code" required><input name="barcode" placeholder="Barcode/QR Code"><input name="name" placeholder="Item Name" required><select name="category_id"><option value="">Category</option><?php foreach($cats as $c) echo '<option value="'.$c['id'].'">'.e($c['name']).'</option>'; ?></select><input name="unit" placeholder="Unit e.g. pcs, box" required><input name="brand" placeholder="Brand"><input name="location" placeholder="Location"><input name="rack" placeholder="Rack"><input name="shelf" placeholder="Shelf"><input name="min_stock" type="number" step="0.01" placeholder="Minimum Stock"><input name="current_stock" type="number" step="0.01" placeholder="Opening Stock"><input name="unit_price" type="number" step="0.01" placeholder="Unit Price"><button>Add Item</button></form></div><div class="card"><button onclick="exportTableCSV('tbl','items.csv')">Export CSV</button> <button onclick="printPage()">Print</button><table id="tbl"><tr><th>Code</th><th>Name</th><th>Category</th><th>Balance</th><th>Min</th><th>Status</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['item_code'])?></td><td><?=e($r['name'])?></td><td><?=e($r['cat'])?></td><td><?=e($r['current_stock'].' '.$r['unit'])?></td><td><?=e($r['min_stock'])?></td><td class="<?=$r['current_stock']<=$r['min_stock']?'low':'ok'?>"><?=$r['current_stock']<=$r['min_stock']?'LOW':'OK'?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
